// 見積書生成モーダルを開く
function generateQuotePdf(oppId) {
  const o = db.opportunities.find(x => x.id === oppId);
  if(!o) return;

  // 見積モーダルの入力値をリセット・初期化
  document.getElementById('q-customer').value  = o.customer || '';
  document.getElementById('q-subject').value   = o.name    || '';
  document.getElementById('q-owner').value     = o.owner   || (currentUser?.name || '');
  document.getElementById('q-sales-rep').value   = currentUser?.name || o.owner || '';
  const initRepUser = db.users.find(u => u.name === (currentUser?.name || o.owner || ''));
  document.getElementById('q-sales-email').value = initRepUser?.email || COMPANY_INFO.email;
  document.getElementById('q-sales-tel').value   = COMPANY_INFO.tel;
  document.getElementById('q-date').value      = new Date().toISOString().split('T')[0];
  const _qOppId = document.getElementById('q-opp-id').value || '';
  document.getElementById('q-no').value        = 'Q-' + new Date().getFullYear() + '-' + (_qOppId || String(Date.now()).slice(-6));
  document.getElementById('q-valid').value     = 'お打合せの通り';
  document.getElementById('q-payment').value   = 'お打合せの通り';
  document.getElementById('q-delivery').value  = 'お打合せの通り';
  document.getElementById('q-notes').value     = '';
  document.getElementById('q-opp-id').value    = oppId;

  // 明細を案件金額から初期設定（1行）
  const tbody = document.getElementById('q-items-tbody');
  tbody.innerHTML = '';
  addQuoteItem(o.name || '業務委託費', 1, (o.amount || 0) * 10000, false);

  renderQuoteTotals();
  openModal('quote-maker');
}

function addQuoteItem(name, qty, price, isOpt) {
  const tbody = document.getElementById('q-items-tbody');
  const tr = document.createElement('tr');
  tr.innerHTML =
    '<td><input class="form-control" style="width:100%;font-size:12px;" value="' + (name||'') + '"></td>' +
    '<td><select class="form-control" style="font-size:12px;">' +
      '<option value="1">1</option><option value="1" selected>1</option>' +
    '</select></td>' +
    '<td><input class="form-control" style="font-size:12px;text-align:right;" type="number" value="' + (price||0) + '" oninput="renderQuoteTotals()"></td>' +
    '<td style="text-align:right;font-size:12px;" class="q-amount-cell">' + Number(price||0).toLocaleString() + '</td>' +
    '<td style="text-align:center;"><input type="checkbox"' + (isOpt?' checked':'') + '></td>' +
    '<td style="text-align:center;"><button class="btn btn-sm btn-danger" style="padding:2px 6px;" onclick="this.closest(\'tr\').remove();renderQuoteTotals();">×</button></td>';
  tbody.appendChild(tr);
}

function renderQuoteTotals() {
  let subtotal = 0;
  document.querySelectorAll('#q-items-tbody tr').forEach(tr => {
    const priceEl = tr.querySelector('input[type="number"]');
    const amtEl   = tr.querySelector('.q-amount-cell');
    if(priceEl && amtEl) {
      const v = parseFloat(priceEl.value) || 0;
      subtotal += v;
      amtEl.textContent = v.toLocaleString();
    }
  });
  const tax   = Math.round(subtotal * 0.1);
  const total = subtotal + tax;
  document.getElementById('q-subtotal').textContent = '¥' + subtotal.toLocaleString();
  document.getElementById('q-tax').textContent      = '¥' + tax.toLocaleString();
  document.getElementById('q-total').textContent    = '¥' + total.toLocaleString();
  document.getElementById('q-total-header').textContent = '¥' + total.toLocaleString();
}

// 見積書PDF生成・案件に保存
// 見積書を直接案件に保存（プレビュー不要）
function saveQuoteDirectly() {
  const oppId    = document.getElementById('q-opp-id').value;
  const customer = document.getElementById('q-customer').value.trim();
  const subject  = document.getElementById('q-subject').value.trim();
  const qNo      = document.getElementById('q-no').value.trim();

  if(!oppId) { toast('案件IDが取得できません', 'error'); return; }

  // 見積書HTMLを生成して保存
  buildQuoteHtmlAndSave(oppId, qNo, customer);
}

// HTML生成して案件に保存する共通処理
function buildQuoteHtmlAndSave(oppId, qNo, customer) {
  // buildAndSaveQuote と同じ printHtml を生成して保存のみ行う
  const btn = event?.target;
  if(btn) { btn.disabled = true; btn.textContent = '保存中...'; }

  // 非同期で HTML を生成
  const printHtml = _buildQuoteHtml();
  if(!printHtml) { if(btn) { btn.disabled = false; btn.textContent = '💾 案件に保存'; } return; }

  const blob = new Blob([_fixQuoteHtml(printHtml)], {type: 'text/html;charset=utf-8'});
  const reader = new FileReader();
  reader.onload = function(e) {
    const fname = customer + '様_概算御見積書_' + qNo + '.html';
    const files = getPdfFiles(oppId, 'estimate');
    const existing = files.findIndex(f => f.name === fname);
    const entry = {name: fname, data: e.target.result, size: blob.size, date: new Date().toISOString()};
    if(existing >= 0) files[existing] = entry; else files.push(entry);
    savePdfFiles(oppId, 'estimate', files);
    save();
    // 案件フェーズを「見積提出」に変更
    const _oi = db.opportunities.findIndex(o => o.id === oppId);
    if(_oi >= 0 && db.opportunities[_oi].stage !== '受注' && db.opportunities[_oi].stage !== '失注') {
      db.opportunities[_oi].stage = '見積提出';
      db.opportunities[_oi].prob  = STAGE_PROB['見積提出'] ?? db.opportunities[_oi].prob;
      db.opportunities[_oi].lastUpdated = new Date().toISOString().split('T')[0];
    }
    save();
    closeModal('quote-maker');
    showClapAnimation();
    toast('見積書を案件に保存しました。フェーズを「見積提出」に更新しました。', 'success');
    if(currentDetailOppId === oppId) showOppDetail(oppId);
    renderOpportunities();
    if(btn) { btn.disabled = false; btn.textContent = '💾 案件に保存'; }
  };
  reader.readAsDataURL(blob);
}

// 見積書HTMLの分割スクリプトタグを元に戻す
function _fixQuoteHtml(h) {
  return h
    .replace(/<scr'+'ipt>/g, '<'+'script>')
    .replace(/<\/scr'+'ipt>/g, '</'+'script>');
}

