async function buildAndSaveQuote() {
  const printHtml = _buildQuoteHtml();
  if(!printHtml) return;

  const oppId    = document.getElementById('q-opp-id').value;
  const qNo      = document.getElementById('q-no').value.trim();
  const customer = document.getElementById('q-customer').value.trim();
  const saveData = { oppId, qNo, customer, html: printHtml };

  const win = window.open('', '_blank', 'width=960,height=1100');
  if(!win) { toast('ポップアップがブロックされました。', 'error'); return; }

  // window.opener 経由で保存できるよう _saveQuotePdf を設定
  window._saveQuotePdf = function(oid, q, dataUrl) {
    try {
      const files = getPdfFiles(oid, 'estimate');
      const cust  = db.opportunities.find(o=>o.id===oid)?.customer || customer;
      const fname = (cust ? cust+'様_' : '') + '概算御見積書_' + q + '.html';
      const entry = {name: fname, data: dataUrl, size: dataUrl.length, date: new Date().toISOString()};
      const ex = files.findIndex(f => f.name === fname);
      if(ex >= 0) files[ex] = entry; else files.push(entry);
      savePdfFiles(oid, 'estimate', files);
      const oi = db.opportunities.findIndex(o => o.id === oid);
      if(oi >= 0 && db.opportunities[oi].stage !== '受注' && db.opportunities[oi].stage !== '失注') {
        db.opportunities[oi].stage = '見積提出';
        db.opportunities[oi].prob  = STAGE_PROB['見積提出'] ?? db.opportunities[oi].prob;
      }
      save();
      toast('見積書を案件に保存しました。フェーズを「見積提出」に更新しました。', 'success');
      if(currentDetailOppId === oid) showOppDetail(oid);
      renderOpportunities();
      // プレビューウィンドウを閉じてから親ウィンドウにフォーカスしてアニメーション
      try { if(window.opener && !window.opener.closed) window.opener.focus(); } catch(e){}
      setTimeout(() => {
        window.focus();
        showClapAnimation();
      }, 500);
      return true;
    } catch(e) { toast('保存エラー: '+e.message, 'error'); return false; }
  };

  // <scr'+'ipt> を実際の script タグに変換して書き込む
  const _html = printHtml
    .replace(/<scr'\+'ipt>/g, '<'+'script>')
    .replace(/<\/scr'\+'ipt>/g, '</'+'script>');
  win.document.write(_html);
  win.document.close();
  toast('見積書を開きました。', 'success');
  closeModal('quote-maker');
}


// ============================================================
// 🎉 受注お祝いアニメーション（クラッカー×2）
// ============================================================
function showCrackerAnimation() {
  const container = document.createElement('div');
  container.style.cssText = [
    'position:fixed', 'inset:0', 'pointer-events:none',
    'z-index:9999', 'display:flex', 'align-items:center',
    'justify-content:center', 'gap:40px',
  ].join(';');

  // クラッカー2つ + お祝いメッセージ
  const msg = document.createElement('div');
  msg.style.cssText = [
    'position:absolute', 'top:50%', 'left:50%',
    'transform:translate(-50%,-50%) scale(0)',
    'background:linear-gradient(135deg,#fff9e6,#fff)',
    'border:3px solid #f0c040',
    'border-radius:16px', 'padding:18px 36px',
    'font-size:22px', 'font-weight:700', 'color:#b8860b',
    'text-align:center', 'white-space:nowrap',
    'box-shadow:0 8px 32px rgba(0,0,0,0.18)',
    'transition:transform 0.5s cubic-bezier(0.34,1.56,0.64,1)',
  ].join(';');
  msg.innerHTML = '🎉 受注おめでとうございます！ 🎉';
  container.appendChild(msg);

  document.body.appendChild(container);

  // 紙吹雪の色
  const colors = ['#e74c3c','#3498db','#2ecc71','#f39c12','#9b59b6','#1abc9c','#e91e63','#ff9800'];
  const confettiCount = 80;

  for(let i = 0; i < confettiCount; i++) {
    const c = document.createElement('div');
    const color = colors[Math.floor(Math.random() * colors.length)];
    const size  = 6 + Math.random() * 8;
    const startX = 40 + Math.random() * 20; // 左クラッカー付近
    const startX2 = 78 + Math.random() * 20; // 右クラッカー付近
    const x = i < confettiCount / 2 ? startX : startX2;
    const angle = -60 + Math.random() * 120;
    const distance = 100 + Math.random() * 200;
    const duration = 1.5 + Math.random() * 1.5;
    const delay    = Math.random() * 0.6;
    c.style.cssText = [
      'position:fixed',
      `left:${x}%`, 'top:45%',
      `width:${size}px`, `height:${size * 0.6}px`,
      `background:${color}`,
      'border-radius:2px',
      `transform:rotate(${Math.random()*360}deg)`,
      `opacity:1`,
      `transition:all ${duration}s ease-out ${delay}s`,
    ].join(';');
    container.appendChild(c);
    requestAnimationFrame(() => requestAnimationFrame(() => {
      const rad = angle * Math.PI / 180;
      const tx  = Math.cos(rad) * distance * (i < confettiCount/2 ? -1 : 1);
      const ty  = -Math.abs(Math.sin(rad) * distance) - 80;
      c.style.transform = `translate(${tx}px,${ty}px) rotate(${Math.random()*720}deg)`;
      c.style.opacity   = '0';
    }));
  }

  // クラッカー絵文字
  ['🎊', '🎊'].forEach((emoji, idx2) => {
    const el = document.createElement('div');
    el.style.cssText = [
      'position:absolute', 'font-size:80px',
      `${idx2 === 0 ? 'left:20%' : 'right:20%'}`, 'top:50%',
      'transform:translateY(-50%) scale(0)',
      `transition:transform 0.4s cubic-bezier(0.34,1.56,0.64,1) ${idx2 * 0.15}s`,
    ].join(';');
    el.textContent = emoji;
    container.appendChild(el);
    requestAnimationFrame(() => requestAnimationFrame(() => {
      el.style.transform = `translateY(-50%) scale(1) rotate(${idx2 === 0 ? -15 : 15}deg)`;
    }));
  });

  // メッセージ表示
  setTimeout(() => { msg.style.transform = 'translate(-50%,-50%) scale(1)'; }, 300);

  // フェードアウト
  setTimeout(() => {
    container.style.transition = 'opacity 0.8s ease';
    container.style.opacity = '0';
  }, 3000);
  setTimeout(() => container.remove(), 3800);
}

// ============================================================
// 👏 見積書保存成功アニメーション
// ============================================================
function showClapAnimation() {
  const el = document.createElement('div');
  el.style.cssText = [
    'position:fixed',
    'top:50%',
    'left:50%',
    'transform:translate(-50%,-50%) scale(0.3)',
    'font-size:110px',
    'z-index:9999',
    'pointer-events:none',
    'opacity:0',
    'transition:transform 0.4s cubic-bezier(0.34,1.56,0.64,1), opacity 0.3s ease',
  ].join(';');
  el.textContent = '👏';
  document.body.appendChild(el);

  // フレーム1: ポップアップ
  requestAnimationFrame(() => requestAnimationFrame(() => {
    el.style.transform = 'translate(-50%,-50%) scale(1.1)';
    el.style.opacity   = '1';
  }));

  // フレーム2〜: パルス（拍手リズム）
  const pulses = [
    {delay: 400,  scale: '0.85', dur: '0.15s'},
    {delay: 600,  scale: '1.1',  dur: '0.15s'},
    {delay: 800,  scale: '0.85', dur: '0.15s'},
    {delay: 1000, scale: '1.1',  dur: '0.15s'},
    {delay: 1200, scale: '0.85', dur: '0.15s'},
    {delay: 1400, scale: '1.1',  dur: '0.15s'},
  ];
  pulses.forEach(p => {
    setTimeout(() => {
      el.style.transition = 'transform ' + p.dur + ' ease-in-out';
      el.style.transform  = 'translate(-50%,-50%) scale(' + p.scale + ')';
    }, p.delay);
  });

  // フェードアウト（2.3秒〜2.9秒）
  setTimeout(() => {
    el.style.transition = 'opacity 0.6s ease, transform 0.6s ease';
    el.style.opacity    = '0';
    el.style.transform  = 'translate(-50%,-60%) scale(0.8)';
  }, 2300);
  setTimeout(() => el.remove(), 2900);
}

